import cv2
import numpy as np
from PIL import Image


def extract_text(img) -> Image:
    gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
    _, thresh = cv2.threshold(gray, 150, 255, cv2.THRESH_BINARY)
    dilated = cv2.dilate(thresh, np.ones((2, 2), np.uint8), iterations=1)
    contours, _ = cv2.findContours(dilated, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)

    text_img = np.ones_like(img) * 255  # Create a white image for text
    cv2.drawContours(text_img, contours, -1, (0, 0, 0), 2)  # Draw contours

    return Image.fromarray(text_img)


def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        processed_img = extract_text(img)

        output_path = "artifacts/chart_text_extractor_output.png"
        save_image(processed_img, output_path)

        return ToolResult(
            status="ok",
            answer="",
            artifacts=[output_path],
        )
    except Exception as e:
        return ToolResult(status="error", answer="", error=str(e))


