from core.types import ToolResult
from tools.implementations.shared import load_image, save_image
import cv2
import pytesseract
import numpy as np

pytesseract.pytesseract.tesseract_cmd = r'/usr/bin/tesseract'

def preprocess_for_ocr(img):
    gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
    _, thresh = cv2.threshold(gray, 150, 255, cv2.THRESH_BINARY_INV)
    return thresh

def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        processed_img = preprocess_for_ocr(img)

        text_data = pytesseract.image_to_data(processed_img, output_type=pytesseract.Output.DICT)
        extracted_texts = list(zip(text_data['text'], text_data['left'], text_data['top'], text_data['width'], text_data['height']))

        year_2019_value = ""

        for text, x, y, w, h in extracted_texts:
            if text.strip().isdigit() and '2019' in text_data['text']:
                if 2019 - int(text) <= 2:
                    year_2019_value = text
                    cv2.rectangle(img, (x, y), (x + w, y + h), (0, 255, 0), 2)
                    break

        output_path = "artifacts/extract_chart_labels_2019_output.png"
        save_image(img, output_path)

        return ToolResult(
            status="ok",
            answer=f"Extracted 2019 GDP value: {year_2019_value}",
            artifacts=[output_path],
        )
    except Exception as e:
        return ToolResult(status="error", answer="", error=str(e))

def main():
    import sys
    if len(sys.argv) < 2:
        print(f"Usage: python {sys.argv[0]} <image_path>")
        sys.exit(1)

    print(run(sys.argv[1]))

if __name__ == "__main__":
    main()

from core.types import ToolResult
from tools.implementations.shared import load_image, save_image
import cv2
import numpy as np
from PIL import Image


def extract_text_regions(image):
    gray = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
    _, binary = cv2.threshold(gray, 128, 255, cv2.THRESH_BINARY)
    contours, _ = cv2.findContours(binary, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
    return contours


def filter_for_gdp_data(contours):
    filtered_contours = [c for c in contours if cv2.contourArea(c) > 50]
    return filtered_contours


def overlay_contours_on_image(image, contours):
    overlay_img = image.copy()
    cv2.drawContours(overlay_img, contours, -1, (0, 255, 0), 2)
    return overlay_img


def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        contours = extract_text_regions(img)
        data_contours = filter_for_gdp_data(contours)
        processed_img = overlay_contours_on_image(img, data_contours)

        output_path = "artifacts/extract_chart_data_output.png"
