from core.types import ToolResult
from tools.implementations.shared import load_image, save_image
import cv2
import numpy as np

COLOR_CODES = {
    'Asia Pacific & Middle East': (192, 0, 0)  # RGB color for the region
}


def extract_region_by_color(img, color):
    # Convert image to HSV
    img_hsv = cv2.cvtColor(img, cv2.COLOR_RGB2HSV)
    # Define the range of the color
    color_low = np.array([color[0] - 10, 100, 100])
    color_high = np.array([color[0] + 10, 255, 255])
    # Threshold the HSV image to get only specified colors
    mask = cv2.inRange(img_hsv, color_low, color_high)
    # Bitwise-AND mask and original image
    res = cv2.bitwise_and(img, img, mask=mask)
    return res


def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        # Extract region based on color
        region_img = extract_region_by_color(img, COLOR_CODES['Asia Pacific & Middle East'])

        output_path = "artifacts/extract_region_color_data_output.png"
        save_image(region_img, output_path)

        return ToolResult(
            status="ok",
